225→    fun syncAllToCalendar() {
226→        viewModelScope.launch {
227→            _uiState.update { it.copy(loading = true) }
228→            var synced = 0
229→            // 同步短信中的开庭信息
230→            resyncPendingSms()
231→            // 同步所有PDF
232→            val allPdfs = repo.getAllPdfs().first()
233→            for (pdf in allPdfs) {
234→                if (pdf.calendarEventId != null) continue
235→                val info = pdfParser.parseSubpoena(pdf.filePath) ?: continue
236→                if (info.hearingTime == null || info.caseNumber == null) continue
237→                val eventId = calendarSync.syncHearing(
238→                    caseNumber = info.caseNumber,
239→                    courtName = info.courtName,
240→                    hearingTime = info.hearingTime,
241→                    defendant = info.defendant,
242→                    handler = info.handler,
243→                    location = info.location,
244→                    phone = info.phone,
245→                    caseType = info.caseType
246→                ) ?: continue
247→                val hearingDesc = buildString {
248→                    if (info.courtName != null) append("法院: ${info.courtName}\n")
249→                    if (info.defendant != null) append("被传唤人: ${info.defendant}\n")
250→                    if (info.handler != null) append("承办人: ${info.handler}\n")
251→                    if (info.location != null) append("地点: ${info.location}")
252→                    if (info.phone != null) append("\n电话: ${info.phone}")
253→                }.takeIf { it.isNotBlank() }
254→                repo.updatePdf(pdf.copy(isSubpoena = true, hearingInfo = hearingDesc, calendarEventId = eventId))
255→                synced++
256→            }
257→            _uiState.update { it.copy(loading = false, message = if (synced > 0) "已同步 $synced 条日程" else "没有新的日程需要同步") }
258→        }
259→    }
