261→    /**
262→     * 手动同步PDF到日程
263→     */
264→    fun syncPdfToCalendar(pdfId: Long) {
265→        viewModelScope.launch {
266→            val pdf = repo.getPdfById(pdfId) ?: return@launch
267→            val info = pdfParser.parseSubpoena(pdf.filePath)
268→
269→            if (info == null) {
270→                _uiState.update { it.copy(message = "无法解析文件内容") }
271→                return@launch
272→            }
273→
274→            if (info.hearingTime == null || info.caseNumber == null) {
275→                _uiState.update { it.copy(message = "未找到开庭时间或案号") }
276→                return@launch
277→            }
278→
279→            val eventId = calendarSync.syncHearing(
280→                caseNumber = info.caseNumber,
281→                courtName = info.courtName,
282→                hearingTime = info.hearingTime,
283→                defendant = info.defendant,
284→                handler = info.handler,
285→                location = info.location,
286→                phone = info.phone,
287→                caseType = info.caseType
288→            )
289→
290→            if (eventId != null) {
291→                val hearingDesc = buildString {
292→                    if (info.courtName != null) append("法院: ${info.courtName}\n")
293→                    if (info.defendant != null) append("被传唤人: ${info.defendant}\n")
294→                    if (info.handler != null) append("承办人: ${info.handler}\n")
295→                    if (info.location != null) append("地点: ${info.location}")
296→                    if (info.phone != null) append("\n电话: ${info.phone}")
297→                }.takeIf { it.isNotBlank() }
298→                repo.updatePdf(pdf.copy(isSubpoena = true, hearingInfo = hearingDesc, calendarEventId = eventId))
299→                _uiState.update { it.copy(message = "已添加到日历") }
300→            } else {
301→                _uiState.update { it.copy(message = "日历事件已存在") }
302→            }
303→        }
304→    }
