306→    fun sharePdfs(pdfIds: List<Long>) {
307→        viewModelScope.launch {
308→            val pdfs = pdfIds.mapNotNull { repo.getPdfById(it) }
309→            if (pdfs.isEmpty()) return@launch
310→
311→            val ctx = getApplication<CourtApp>()
312→            val authority = "${ctx.packageName}.fileprovider"
313→
314→            if (pdfs.size == 1) {
315→                val file = File(pdfs[0].filePath)
316→                if (!file.exists()) { _uiState.update { it.copy(message = "文件不存在") }; return@launch }
317→                val uri = FileProvider.getUriForFile(ctx, authority, file)
318→                val intent = Intent(Intent.ACTION_SEND).apply {
319→                    type = "application/pdf"
320→                    putExtra(Intent.EXTRA_STREAM, uri)
321→                    addFlags(Intent.FLAG_GRANT_READ_URI_PERMISSION or Intent.FLAG_ACTIVITY_NEW_TASK)
322→                }
323→                ctx.startActivity(Intent.createChooser(intent, "分享文书").addFlags(Intent.FLAG_ACTIVITY_NEW_TASK))
324→            } else {
325→                val zipFile = withContext(Dispatchers.IO) {
326→                    val dir = File(ctx.getExternalFilesDir(null), "Zips")
327→                    if (!dir.exists()) dir.mkdirs()
328→                    val zip = File(dir, "法院文书_${System.currentTimeMillis()}.zip")
329→                    ZipOutputStream(zip.outputStream()).use { zos ->
330→                        for (pdf in pdfs) {
331→                            val f = File(pdf.filePath)
332→                            if (!f.exists()) continue
333→                            zos.putNextEntry(ZipEntry(pdf.fileName))
334→                            f.inputStream().use { it.copyTo(zos) }
335→                            zos.closeEntry()
336→                        }
337→                    }
338→                    zip
339→                }
340→                val uri = FileProvider.getUriForFile(ctx, authority, zipFile)
341→                val intent = Intent(Intent.ACTION_SEND).apply {
342→                    type = "application/zip"
343→                    putExtra(Intent.EXTRA_STREAM, uri)
344→                    addFlags(Intent.FLAG_GRANT_READ_URI_PERMISSION or Intent.FLAG_ACTIVITY_NEW_TASK)
345→                }
346→                ctx.startActivity(Intent.createChooser(intent, "分享文书").addFlags(Intent.FLAG_ACTIVITY_NEW_TASK))
347→            }
348→        }
349→    }
350→}
