178→private fun parseContentDispositionFileName(contentDisposition: String?): String? {
179→    if (contentDisposition == null) return null
180→    Regex("""filename\*=(?:UTF-8''|utf-8'')(.+)""").find(contentDisposition)?.let {
181→        return try { java.net.URLDecoder.decode(it.groupValues[1], "UTF-8") } catch (_: Exception) { null }
182→    }
183→    Regex("filename=\"?([^\"]+)\"?").find(contentDisposition)?.let {
184→        return it.groupValues[1].trim()
185→    }
186→    return null
187→}
188→
189→private fun extractFileNameFromUrl(url: String): String? {
190→    val path = url.substringBefore("?").substringAfterLast("/")
191→    val decoded = try { java.net.URLDecoder.decode(path, "UTF-8") } catch (_: Exception) { path }
192→    return decoded.takeIf { it.contains(".") && it.length > 4 }
193→}
