@Dao
interface CourtDao {
    @Query("SELECT * FROM court_sms ORDER BY receivedAt DESC")
    fun getAllSms(): Flow<List<CourtSmsEntity>>

    @Query("SELECT * FROM court_sms ORDER BY receivedAt DESC")
    suspend fun getAllSmsList(): List<CourtSmsEntity>

    @Query("SELECT * FROM court_sms WHERE id = :id")
    suspend fun getSmsById(id: Long): CourtSmsEntity?

    @Insert(onConflict = OnConflictStrategy.IGNORE)
    suspend fun insertSms(sms: CourtSmsEntity): Long

    @Update
    suspend fun updateSms(sms: CourtSmsEntity)

    @Query("SELECT * FROM pdf_documents WHERE smsId = :smsId ORDER BY downloadedAt")
    fun getPdfsBySmsId(smsId: Long): Flow<List<PdfDocumentEntity>>

    @Query("SELECT * FROM pdf_documents ORDER BY downloadedAt DESC")
    fun getAllPdfs(): Flow<List<PdfDocumentEntity>>

    @Insert(onConflict = OnConflictStrategy.IGNORE)
    suspend fun insertPdf(pdf: PdfDocumentEntity): Long

    @Update
    suspend fun updatePdf(pdf: PdfDocumentEntity)

    @Query("SELECT * FROM pdf_documents WHERE id = :id")
    suspend fun getPdfById(id: Long): PdfDocumentEntity?

    @Query("SELECT EXISTS(SELECT 1 FROM court_sms WHERE bodyHash = :hash)")
    suspend fun smsExists(hash: Int): Boolean

    @Query("SELECT EXISTS(SELECT 1 FROM pdf_documents WHERE filePath = :filePath)")
    suspend fun pdfExists(filePath: String): Boolean

    @Query("SELECT EXISTS(SELECT 1 FROM pdf_documents WHERE fileMd5 = :md5)")
    suspend fun pdfExistsByMd5(md5: String): Boolean

    @Query("SELECT * FROM pdf_documents WHERE fileMd5 = :md5 LIMIT 1")
    suspend fun getPdfByMd5(md5: String): PdfDocumentEntity?

    @Query("SELECT id FROM pdf_documents WHERE filePath = :filePath LIMIT 1")
    suspend fun getPdfIdByPath(filePath: String): Long?

    @Query("DELETE FROM pdf_documents WHERE id = :id")
    suspend fun deletePdf(id: Long)

    @Query("DELETE FROM court_sms")
    suspend fun clearAllSms()

    @Query("DELETE FROM pdf_documents")
    suspend fun clearAllPdfs()
}

package com.court.assistant.data.db

import android.content.Context
import androidx.room.migration.Migration
import androidx.sqlite.db.SupportSQLiteDatabase
import androidx.room.*

val MIGRATION_1_2 = object : Migration(1, 2) {
    override fun migrate(database: SupportSQLiteDatabase) {
        // 删除旧表并重建，添加 fileMd5 和 ocrTitle 列
        database.execSQL("DROP TABLE IF EXISTS pdf_documents")
        database.execSQL("""
            CREATE TABLE IF NOT EXISTS pdf_documents (
                id INTEGER PRIMARY KEY AUTOINCREMENT NOT NULL,
                smsId INTEGER NOT NULL,
                fileName TEXT NOT NULL,
                filePath TEXT NOT NULL,
                fileSize INTEGER NOT NULL,
                fileMd5 TEXT NOT NULL,
                ocrTitle TEXT,
                downloadedAt INTEGER NOT NULL,
                isSubpoena INTEGER NOT NULL DEFAULT 0,
                hearingInfo TEXT,
                calendarEventId INTEGER,
                FOREIGN KEY(smsId) REFERENCES court_sms(id) ON DELETE CASCADE
            )
        """)
        database.execSQL("CREATE INDEX IF NOT EXISTS index_pdf_documents_smsId ON pdf_documents(smsId)")
        database.execSQL("CREATE UNIQUE INDEX IF NOT EXISTS index_pdf_documents_fileMd5 ON pdf_documents(fileMd5)")
    }
}

val MIGRATION_2_3 = object : Migration(2, 3) {
    override fun migrate(database: SupportSQLiteDatabase) {
        // 重建pdf_documents表，改为 smsId+fileMd5 联合唯一索引
        database.execSQL("DROP TABLE IF EXISTS pdf_documents")
        database.execSQL("""
            CREATE TABLE IF NOT EXISTS pdf_documents (
                id INTEGER PRIMARY KEY AUTOINCREMENT NOT NULL,
                smsId INTEGER NOT NULL,
                fileName TEXT NOT NULL,
                filePath TEXT NOT NULL,
                fileSize INTEGER NOT NULL,
                fileMd5 TEXT NOT NULL,
                ocrTitle TEXT,
                downloadedAt INTEGER NOT NULL,
                isSubpoena INTEGER NOT NULL DEFAULT 0,
                hearingInfo TEXT,
                calendarEventId INTEGER,
                FOREIGN KEY(smsId) REFERENCES court_sms(id) ON DELETE CASCADE
            )
        """)
        database.execSQL("CREATE INDEX IF NOT EXISTS index_pdf_documents_smsId ON pdf_documents(smsId)")
        database.execSQL("CREATE UNIQUE INDEX IF NOT EXISTS index_pdf_documents_smsId_fileMd5 ON pdf_documents(smsId, fileMd5)")
    }
}

@Database(
    entities = [CourtSmsEntity::class, PdfDocumentEntity::class],
    version = 3,
    exportSchema = false
)
abstract class CourtDatabase : RoomDatabase() {
    abstract fun courtDao(): CourtDao

    companion object {
        @Volatile
        private var INSTANCE: CourtDatabase? = null

        fun getInstance(context: Context): CourtDatabase {
            return INSTANCE ?: synchronized(this) {
                Room.databaseBuilder(
                    context.applicationContext,
                    CourtDatabase::class.java,
                    "court_assistant.db"
                )
                .addMigrations(MIGRATION_1_2, MIGRATION_2_3)
                .build().also { INSTANCE = it }
            }
        }
    }
}

