@OptIn(ExperimentalFoundationApi::class)
@Composable
fun PdfCard(pdf: PdfDocumentEntity, selected: Boolean, onClick: () -> Unit, onLongClick: () -> Unit, onSyncCalendar: (() -> Unit)? = null) {
    val dateFormat = remember { SimpleDateFormat("MM-dd HH:mm", Locale.CHINA) }
    val borderColor = if (selected) CinnabarRed else MistGray
    val bgColor = if (selected) CinnabarRed.copy(alpha = 0.06f) else WarmWhite
    Surface(
        modifier = Modifier
            .fillMaxWidth()
            .clip(RoundedCornerShape(6.dp))
            .border(if (selected) 1.5.dp else 0.5.dp, borderColor, RoundedCornerShape(6.dp))
            .combinedClickable(onClick = onClick, onLongClick = onLongClick),
        color = bgColor,
        shape = RoundedCornerShape(6.dp)
    ) {
        Column {
            Row(
                modifier = Modifier.padding(10.dp),
                verticalAlignment = Alignment.CenterVertically
            ) {
                if (selected) {
                    Checkbox(
                        checked = true,
                        onCheckedChange = { onLongClick() },
                        modifier = Modifier.size(20.dp),
                        colors = CheckboxDefaults.colors(checkedColor = CinnabarRed)
                    )
                    Spacer(modifier = Modifier.width(6.dp))
                } else {
                    Text(
                        if (pdf.isSubpoena) "📋" else "📄",
                        style = MaterialTheme.typography.titleLarge
                    )
                    Spacer(modifier = Modifier.width(8.dp))
                }
                Column(modifier = Modifier.weight(1f)) {
                    Text(
                        pdf.fileName,
                        style = MaterialTheme.typography.bodyMedium,
                        color = InkBlack,
                        maxLines = 1,
                        overflow = TextOverflow.Ellipsis
                    )
                    Text(
                        "${dateFormat.format(Date(pdf.downloadedAt))} · ${formatSize(pdf.fileSize)}",
                        style = MaterialTheme.typography.labelSmall,
                        color = CharcoalGray
                    )
                }
                if (pdf.calendarEventId != null) {
                    Text("已同步日历", style = MaterialTheme.typography.labelSmall, color = JadeGreen)
                }
            }
            if (pdf.isSubpoena && pdf.calendarEventId == null && onSyncCalendar != null) {
                Button(
                    onClick = onSyncCalendar,
                    modifier = Modifier
                        .fillMaxWidth()
                        .padding(start = 10.dp, end = 10.dp, bottom = 8.dp),
                    colors = ButtonDefaults.buttonColors(
                        containerColor = AmberGold,
                        contentColor = WarmWhite
                    ),
                    shape = RoundedCornerShape(6.dp),
                    contentPadding = PaddingValues(vertical = 6.dp)
                ) {
                    Icon(Icons.Default.DateRange, contentDescription = null, modifier = Modifier.size(16.dp))
                    Spacer(modifier = Modifier.width(4.dp))
                    Text("一键同步日历")
                }
            }
        }
    }
}

private fun formatSize(bytes: Long): String {
    return when {
        bytes < 1024 -> "${bytes}B"
        bytes < 1024 * 1024 -> "${bytes / 1024}KB"
        else -> String.format("%.1fMB", bytes / (1024.0 * 1024.0))
    }
}

