263→    /**
264→     * 手动同步PDF到日程
265→     */
266→    fun syncPdfToCalendar(pdfId: Long) {
267→        viewModelScope.launch {
268→            val pdf = repo.getPdfById(pdfId) ?: return@launch
269→            val info = pdfParser.parseSubpoena(pdf.filePath)
270→
271→            if (info == null) {
272→                _uiState.update { it.copy(message = "无法解析文件内容") }
273→                return@launch
274→            }
275→
276→            if (info.hearingTime == null || info.caseNumber == null) {
277→                _uiState.update { it.copy(message = "未找到开庭时间或案号") }
278→                return@launch
279→            }
280→
281→            val eventId = calendarSync.syncHearing(
282→                caseNumber = info.caseNumber,
283→                courtName = info.courtName,
284→                hearingTime = info.hearingTime,
285→                defendant = info.defendant,
286→                handler = info.handler,
287→                location = info.location,
288→                phone = info.phone,
289→                caseType = info.caseType
290→            )
291→
292→            if (eventId != null) {
293→                val hearingDesc = buildString {
294→                    if (info.courtName != null) append("法院: ${info.courtName}\n")
295→                    if (info.defendant != null) append("被传唤人: ${info.defendant}\n")
296→                    if (info.handler != null) append("承办人: ${info.handler}\n")
297→                    if (info.location != null) append("地点: ${info.location}")
298→                    if (info.phone != null) append("\n电话: ${info.phone}")
299→                }.takeIf { it.isNotBlank() }
300→                repo.updatePdf(pdf.copy(isSubpoena = true, hearingInfo = hearingDesc, calendarEventId = eventId))
301→                _uiState.update { it.copy(message = "已添加到日历") }
302→            } else {
303→                _uiState.update { it.copy(message = "日历事件已存在") }
304→            }
305→        }
306→    }
307→
308→    fun sharePdfs(pdfIds: List<Long>) {
309→        viewModelScope.launch {
310→            val pdfs = pdfIds.mapNotNull { repo.getPdfById(it) }
311→            if (pdfs.isEmpty()) return@launch
312→
313→            val ctx = getApplication<CourtApp>()
314→            val authority = "${ctx.packageName}.fileprovider"
315→
316→            if (pdfs.size == 1) {
317→                val file = File(pdfs[0].filePath)
318→                if (!file.exists()) { _uiState.update { it.copy(message = "文件不存在") }; return@launch }
319→                val uri = FileProvider.getUriForFile(ctx, authority, file)
320→                val intent = Intent(Intent.ACTION_SEND).apply {
321→                    type = "application/pdf"
322→                    putExtra(Intent.EXTRA_STREAM, uri)
323→                    addFlags(Intent.FLAG_GRANT_READ_URI_PERMISSION or Intent.FLAG_ACTIVITY_NEW_TASK)
324→                }
325→                ctx.startActivity(Intent.createChooser(intent, "分享文书").addFlags(Intent.FLAG_ACTIVITY_NEW_TASK))
326→            } else {
327→                val zipFile = withContext(Dispatchers.IO) {
328→                    val dir = File(ctx.getExternalFilesDir(null), "Zips")
329→                    if (!dir.exists()) dir.mkdirs()
330→                    val zip = File(dir, "法院文书_${System.currentTimeMillis()}.zip")
331→                    ZipOutputStream(zip.outputStream()).use { zos ->
332→                        for (pdf in pdfs) {
333→                            val f = File(pdf.filePath)
334→                            if (!f.exists()) continue
335→                            zos.putNextEntry(ZipEntry(pdf.fileName))
336→                            f.inputStream().use { it.copyTo(zos) }
337→                            zos.closeEntry()
338→                        }
339→                    }
340→                    zip
341→                }
342→                val uri = FileProvider.getUriForFile(ctx, authority, zipFile)
343→                val intent = Intent(Intent.ACTION_SEND).apply {
344→                    type = "application/zip"
345→                    putExtra(Intent.EXTRA_STREAM, uri)
346→                    addFlags(Intent.FLAG_GRANT_READ_URI_PERMISSION or Intent.FLAG_ACTIVITY_NEW_TASK)
347→                }
348→                ctx.startActivity(Intent.createChooser(intent, "分享文书").addFlags(Intent.FLAG_ACTIVITY_NEW_TASK))
349→            }
350→        }
351→    }
352→}
