129→                            ViewGroup.LayoutParams.MATCH_PARENT,
130→                            ViewGroup.LayoutParams.MATCH_PARENT
131→                        )
132→                        settings.apply {
133→                            javaScriptEnabled = true
134→                            domStorageEnabled = true
135→                            useWideViewPort = true
136→                            loadWithOverviewMode = true
137→                            allowFileAccess = true
138→                            mixedContentMode = WebSettings.MIXED_CONTENT_ALWAYS_ALLOW
139→                            userAgentString = settings.userAgentString.replace("wv", "")
140→                        }
141→
142→                        webViewClient = CourtWebViewClient(
143→                            onPdfDetected = { pdfUrl ->
144→                                val key = pdfUrl.substringBefore("?")
145→                                if (downloadedUrls.add(key)) {
146→                                    val cookies = CookieManager.getInstance().getCookie(pdfUrl)
147→                                    val nameFromUrl = extractFileNameFromUrl(pdfUrl)
148→                                    viewModel.downloadPdf(pdfUrl, smsId, nameFromUrl, cookies)
149→                                }
150→                            },
151→                            onPageLoaded = { loading = false }
152→                        )
153→
154→                        webChromeClient = object : WebChromeClient() {
155→                            override fun onProgressChanged(view: WebView?, newProgress: Int) {
156→                                if (newProgress >= 100) loading = false
157→                            }
158→                        }
159→
160→                        setDownloadListener { downloadUrl, userAgent, contentDisposition, mimetype, contentLength ->
161→                            val key = downloadUrl.substringBefore("?")
162→                            if (downloadedUrls.add(key)) {
163→                                val cookies = CookieManager.getInstance().getCookie(downloadUrl)
164→                                val fileName = parseContentDispositionFileName(contentDisposition)
165→                                    ?: extractFileNameFromUrl(downloadUrl)
166→                                viewModel.downloadPdf(downloadUrl, smsId, fileName, cookies)
167→                            }
168→                        }
169→
170→                        loadUrl(url)
171→                    }
172→                }
173→            )
174→        }
175→    }
176→}
177→
178→private fun parseContentDispositionFileName(contentDisposition: String?): String? {
179→    if (contentDisposition == null) return null
180→    Regex("""filename\*=(?:UTF-8''|utf-8'')(.+)""").find(contentDisposition)?.let {
181→        return try { java.net.URLDecoder.decode(it.groupValues[1], "UTF-8") } catch (_: Exception) { null }
182→    }
183→    Regex("filename=\"?([^\"]+)\"?").find(contentDisposition)?.let {
184→        return it.groupValues[1].trim()
185→    }
186→    return null
187→}
188→
189→private fun extractFileNameFromUrl(url: String): String? {
190→    val path = url.substringBefore("?").substringAfterLast("/")
191→    val decoded = try { java.net.URLDecoder.decode(path, "UTF-8") } catch (_: Exception) { path }
192→    return decoded.takeIf { it.contains(".") && it.length > 4 }
193→}
