    if (!expanded) selectedIds.clear()

    Card(
        modifier = Modifier
            .fillMaxWidth()
            .border(1.dp, MistGray, RoundedCornerShape(8.dp)),
        shape = RoundedCornerShape(8.dp),
        colors = CardDefaults.cardColors(containerColor = WarmWhite),
        elevation = CardDefaults.cardElevation(defaultElevation = 3.dp)
    ) {
        Column {
            // 头部 - 浅米色背景
            Row(
                modifier = Modifier
                    .fillMaxWidth()
                    .background(Ivory)
                    .clickable { expanded = !expanded }
                    .padding(16.dp),
                verticalAlignment = Alignment.CenterVertically
            ) {
                Column(modifier = Modifier.weight(1f)) {
                    // 当事人（醒目）
                    item.sms.partyNames?.let {
                        Text(
                            it,
                            style = MaterialTheme.typography.titleMedium,
                            color = CinnabarRed
                        )
                        Spacer(modifier = Modifier.height(6.dp))
                    }
                    // 法院 + 案号
                    Row(
                        modifier = Modifier.fillMaxWidth(),
                        horizontalArrangement = Arrangement.SpaceBetween,
                        verticalAlignment = Alignment.CenterVertically
                    ) {
                        item.sms.courtName?.let {
                            Text(
                                it,
                                style = MaterialTheme.typography.bodyLarge,
                                color = InkBlack
                            )
                        }
                        item.sms.caseNumber?.let {
                            Text(
                                it,
                                style = MaterialTheme.typography.bodyMedium,
                                color = CharcoalGray,
                                maxLines = 1,
                                overflow = TextOverflow.Ellipsis
                            )
                        }
                    }
                    Spacer(modifier = Modifier.height(6.dp))
                    // 时间 + 发送者
                    Text(
                        "${dateFormat.format(Date(item.sms.receivedAt))}  ${item.sms.sender}",
                        style = MaterialTheme.typography.labelSmall,
                        color = CharcoalGray
                    )
                    // 文书提示
                    if (item.sms.webUrl != null && item.pdfs.isEmpty()) {
                        Spacer(modifier = Modifier.height(6.dp))
                        Text(
                            "点击展开查看文书",
                            style = MaterialTheme.typography.labelSmall,
                            color = AmberGold
                        )
                    }
                    if (item.pdfs.isNotEmpty()) {
                        Spacer(modifier = Modifier.height(4.dp))
                        Text(
                            "${item.pdfs.size} 个文书",
                            style = MaterialTheme.typography.labelSmall,
                            color = JadeGreen
                        )
                    }
                    // 开庭倒计时红字提示
                    val hearingTime = item.sms.hearingTime
                    if (hearingTime != null && item.pdfs.isNotEmpty()) {
                        Spacer(modifier = Modifier.height(6.dp))
                        Text(
                            formatHearingCountdown(hearingTime),
                            style = MaterialTheme.typography.labelLarge,
                            color = Color.Red
                        )
                    }
                }
                Spacer(modifier = Modifier.width(8.dp))
                Icon(
                    if (expanded) Icons.Default.KeyboardArrowUp else Icons.Default.KeyboardArrowDown,
                    contentDescription = null,
                    tint = CharcoalGray
                )
            }

            AnimatedVisibility(visible = expanded) {
                Column(
                    modifier = Modifier
                        .background(ParchmentBg)
                        .padding(start = 12.dp, end = 12.dp, bottom = 12.dp, top = 8.dp),
                    verticalArrangement = Arrangement.spacedBy(8.dp)
                ) {
                    if (item.sms.webUrl != null) {
                        if (item.pdfs.isEmpty()) {
                            Button(
                                onClick = { onOpenWebView(item.sms.id, item.sms.webUrl!!) },
                                modifier = Modifier.fillMaxWidth(),
                                colors = ButtonDefaults.buttonColors(
                                    containerColor = CinnabarRed,
                                    contentColor = WarmWhite
                                ),
                                shape = RoundedCornerShape(6.dp)
                            ) {
                                Text("打开送达链接下载文书")
                            }
                        } else {
                            OutlinedButton(
                                onClick = { onOpenWebView(item.sms.id, item.sms.webUrl!!) },
                                modifier = Modifier.fillMaxWidth(),
                                colors = ButtonDefaults.outlinedButtonColors(contentColor = CharcoalGray),
                                shape = RoundedCornerShape(6.dp)
                            ) {
                                Text("继续下载文书")
                            }
                        }
                    }
                    item.pdfs.forEach { pdf ->
                        val selected = pdf.id in selectedIds
                        PdfCard(
                            pdf = pdf,
                            selected = selected,
                            onClick = {
                                if (selectedIds.isNotEmpty()) {
                                    if (selected) selectedIds.remove(pdf.id) else selectedIds.add(pdf.id)
                                } else {
                                    onOpenPdf(pdf.id)
                                }
                            },
                            onLongClick = {
                                if (selected) selectedIds.remove(pdf.id) else selectedIds.add(pdf.id)
                            },
                            onSyncCalendar = { onSyncCalendar(pdf.id) }
                        )
                    }
                    // 分享按钮
                    if (item.pdfs.isNotEmpty()) {
                        Row(
                            modifier = Modifier.fillMaxWidth(),
                            horizontalArrangement = Arrangement.End,
                            verticalAlignment = Alignment.CenterVertically
                        ) {
                            if (selectedIds.isNotEmpty()) {
                                Text(
                                    "已选 ${selectedIds.size} 个",
                                    style = MaterialTheme.typography.labelSmall,
                                    color = CharcoalGray
                                )
                                Spacer(modifier = Modifier.width(8.dp))
                            }
                            FilledTonalButton(
                                onClick = {
                                    val ids = if (selectedIds.isNotEmpty()) selectedIds.toList()
                                              else item.pdfs.map { it.id }
                                    onSharePdfs(ids)
                                },
                                colors = ButtonDefaults.filledTonalButtonColors(
                                    containerColor = JadeGreen.copy(alpha = 0.15f),
                                    contentColor = JadeGreen
                                ),
                                shape = RoundedCornerShape(6.dp),
                                contentPadding = PaddingValues(horizontal = 12.dp, vertical = 6.dp)
                            ) {
                                Icon(Icons.Default.Share, contentDescription = null, modifier = Modifier.size(16.dp))
                                Spacer(modifier = Modifier.width(4.dp))
                                Text(if (selectedIds.isNotEmpty()) "分享选中" else "分享全部")
                            }
                        }
                    }
                }
            }
        }
    }
}

