                    Spacer(modifier = Modifier.width(4.dp))
                    Text("一键同步日历")
                }
            }
        }
    }
}

private fun formatSize(bytes: Long): String {
    return when {
        bytes < 1024 -> "${bytes}B"
        bytes < 1024 * 1024 -> "${bytes / 1024}KB"
        else -> String.format("%.1fMB", bytes / (1024.0 * 1024.0))
    }
}

private fun formatHearingCountdown(hearingTimeMs: Long): String {
    val dayNames = arrayOf("周日", "周一", "周二", "周三", "周四", "周五", "周六")
    val tz = TimeZone.getTimeZone("Asia/Shanghai")
    val now = Calendar.getInstance(tz)
    val hearing = Calendar.getInstance(tz).apply { timeInMillis = hearingTimeMs }

    // 计算天数差（按日期算，不按24小时）
    val nowDay = Calendar.getInstance(tz).apply {
        timeInMillis = now.timeInMillis
        set(Calendar.HOUR_OF_DAY, 0); set(Calendar.MINUTE, 0); set(Calendar.SECOND, 0); set(Calendar.MILLISECOND, 0)
    }
    val hearingDay = Calendar.getInstance(tz).apply {
        timeInMillis = hearing.timeInMillis
        set(Calendar.HOUR_OF_DAY, 0); set(Calendar.MINUTE, 0); set(Calendar.SECOND, 0); set(Calendar.MILLISECOND, 0)
    }
    val dayDiff = ((hearingDay.timeInMillis - nowDay.timeInMillis) / (24 * 60 * 60 * 1000)).toInt()

    val dayName = dayNames[hearing.get(Calendar.DAY_OF_WEEK) - 1]
    val daysText = when {
        dayDiff < 0 -> "已过期"
        dayDiff == 0 -> "今天"
        dayDiff == 1 -> "明天"
        else -> "${dayDiff}日后"
    }
    val time = String.format("%02d:%02d", hearing.get(Calendar.HOUR_OF_DAY), hearing.get(Calendar.MINUTE))
    return "$dayName-$daysText$time"
}

private fun parseHearingTimeFromPdfs(pdfs: List<PdfDocumentEntity>): Long? {
    for (pdf in pdfs) {
        val info = pdf.hearingInfo ?: continue
        // 从 hearingInfo 文本中提取日期时间
        val match = Regex("(\\d{4})[年-](\\d{1,2})[月-](\\d{1,2})[日号]?[\\s]*(\\d{1,2})[时点:：](\\d{0,2})").find(info)
            ?: continue
        val hour = match.groupValues[4].toIntOrNull() ?: continue
        val minute = match.groupValues[5].takeIf { it.isNotEmpty() }?.toIntOrNull() ?: 0
        val cal = Calendar.getInstance(TimeZone.getTimeZone("Asia/Shanghai")).apply {
            clear()
            set(match.groupValues[1].toInt(), match.groupValues[2].toInt() - 1, match.groupValues[3].toInt(), hour, minute, 0)
        }
        return cal.timeInMillis
    }
    // 如果有已同步日历的传票PDF，说明有开庭时间，但hearingInfo格式不匹配
    // 尝试从calendarEventId判断
    return null
}

