@OptIn(ExperimentalMaterial3Api::class)
@Composable
fun MainScreen(
    viewModel: MainViewModel,
    onOpenWebView: (smsId: Long, url: String) -> Unit,
    onOpenPdf: (pdfId: Long) -> Unit,
    onOpenSettings: () -> Unit = {}
) {
    val state by viewModel.uiState.collectAsState()
    val snackbarHostState = remember { SnackbarHostState() }
    var showClearDialog by remember { mutableStateOf(false) }

    if (showClearDialog) {
        AlertDialog(
            onDismissRequest = { showClearDialog = false },
            title = { Text("清除所有数据") },
            text = { Text("将清除所有短信记录和已下载的文书，确认清除？") },
            confirmButton = {
                TextButton(onClick = {
                    showClearDialog = false
                    viewModel.clearAllData()
                }) { Text("确认清除", color = CinnabarRed) }
            },
            dismissButton = {
                TextButton(onClick = { showClearDialog = false }) { Text("取消") }
            }
        )
    }

    LaunchedEffect(state.message) {
        state.message?.let {
            snackbarHostState.showSnackbar(it)
            viewModel.clearMessage()
        }
    }

    Scaffold(
        snackbarHost = { SnackbarHost(snackbarHostState) },
        topBar = {
            TopAppBar(
                title = {
                    Text("诉讼日程助手", style = MaterialTheme.typography.headlineMedium)
                },
                actions = {
                    IconButton(onClick = { viewModel.syncAllToCalendar() }) {
                        Icon(Icons.Default.DateRange, contentDescription = "同步日程")
                    }
                    IconButton(onClick = { viewModel.loadSms() }) {
                        Icon(Icons.Default.Refresh, contentDescription = "刷新短信")
                    }
                    IconButton(onClick = { showClearDialog = true }) {
                        Icon(Icons.Default.Delete, contentDescription = "清除数据")
                    }
                    IconButton(onClick = onOpenSettings) {
                        Icon(Icons.Default.Settings, contentDescription = "设置")
                    }
                },
                colors = TopAppBarDefaults.topAppBarColors(
                    containerColor = Ivory,
                    titleContentColor = InkBlack
                )
            )
        },
        bottomBar = {
            Surface(
                color = ParchmentBg,
                tonalElevation = 0.dp
            ) {
                Text(
                    text = "宋式美学，单夫纯律师制作保留权利",
                    style = MaterialTheme.typography.labelSmall,
                    color = CharcoalGray.copy(alpha = 0.6f),
                    modifier = Modifier
                        .fillMaxWidth()
                        .padding(vertical = 8.dp, horizontal = 16.dp)
                )
            }
        }
    ) { padding ->
        Box(modifier = Modifier.fillMaxSize().padding(padding)) {
            if (state.loading) {
                CircularProgressIndicator(
                    modifier = Modifier.align(Alignment.Center),
                    color = CinnabarRed
                )
            } else if (state.smsWithPdfs.isEmpty()) {
                Text(
                    "暂无法院短信\n点击右上角刷新读取",
                    style = MaterialTheme.typography.bodyLarge,
                    color = CharcoalGray,
                    modifier = Modifier.align(Alignment.Center)
                )
            } else {
                LazyColumn(
                    modifier = Modifier
                        .fillMaxSize()
                        .background(MistGray),
                    contentPadding = PaddingValues(12.dp),
                    verticalArrangement = Arrangement.spacedBy(12.dp)
                ) {
                    items(state.smsWithPdfs, key = { it.sms.id }) { item ->
                        SmsMenuCard(
                            item = item,
                            onOpenWebView = onOpenWebView,
                            onOpenPdf = onOpenPdf,
                            onSharePdfs = { viewModel.sharePdfs(it) },
                            onSyncCalendar = { viewModel.syncPdfToCalendar(it) }
                        )
                    }
                }
            }
        }
    }
}

@Composable
fun SmsMenuCard(
    item: SmsWithPdfs,
    onOpenWebView: (smsId: Long, url: String) -> Unit,
    onOpenPdf: (pdfId: Long) -> Unit,
    onSharePdfs: (List<Long>) -> Unit,
    onSyncCalendar: (Long) -> Unit
) {
    var expanded by rememberSaveable { mutableStateOf(false) }
    val selectedIds = remember { mutableStateListOf<Long>() }
    val dateFormat = remember { SimpleDateFormat("yyyy-MM-dd HH:mm", Locale.CHINA) }

    // 清除选中状态当收缩时
    if (!expanded) selectedIds.clear()

    Card(
        modifier = Modifier
            .fillMaxWidth()
            .border(1.dp, MistGray, RoundedCornerShape(8.dp)),
        shape = RoundedCornerShape(8.dp),
